window.__glimweaveBootErrors=[];window.addEventListener('error',function(e){window.__glimweaveBootErrors.push((e.message||'Error')+' @ '+(e.filename||'').split('/').pop()+':'+(e.lineno||0));});window.GW=window.GW||{};window.GW.init=function(){try{var loaded=window.GW.State.load(Date.now()),state=loaded.state;window.GW.Integration.setState(state);window.GW.UI.init();window.GW.UI.refresh(state);window.GW.Integration.start();if(loaded.recovery){window.GW.UI.modal('Save recovery','<p>'+loaded.recovery+'</p><p>The incompatible or damaged stored text was left untouched and a clean in-memory Loom was opened. Import requires a valid version-3 save.</p>',[{label:'Continue'}]);}else if(!state.tutorial.dismissed){window.GW.UI.modal('Welcome to the Living Loom','<p>The Sky Loom produces drifting Glim, but only capture fills your Reservoir. Catch a mote, then place a producer and a capturer to discover the pattern.</p><p>Pointer: click motes and place on the field. Keyboard: Tab to a Weftling, use Left/Right to target a mote and Enter to catch. During placement, use arrows and Enter. Escape cancels.</p>',[{label:'Enter the Loom',run:function(){state.tutorial.dismissed=true;window.GW.State.save(state);}}]);}if(loaded.offline&&loaded.offline.elapsedMs>1000){var o=loaded.offline;window.GW.UI.modal('The Loom worked while away','<p>Elapsed '+Math.floor(o.elapsedMs/1000)+'s · credited '+Math.floor(o.cappedMs/1000)+'s (one-hour cap at 50%).</p><p>Gained '+o.gained.toFixed(1)+' Glim'+(o.lost?' · capacity-limited loss '+o.lost.toFixed(1):'')+'.</p>',[{label:'Continue'}]);}setTimeout(function(){if(window.GW.runSmoke)window.GW.runSmoke();},50);}catch(e){window.__glimweaveBootErrors.push('INIT: '+e.message);document.getElementById('smoke-result').textContent='FAIL '+window.__glimweaveBootErrors.join(' | ');}};
